import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecureFileReadExample {

    public static void main(String[] args) {
        String fileName = "test.txt"; // User-supplied input
        String basePath = "/path/to/files/";

        try {
            File file = Paths.get(basePath, fileName).toFile();

            if (file.getCanonicalPath().startsWith(new File(basePath).getCanonicalPath())) {
                FileInputStream fis = new FileInputStream(file);
                byte[] data = new byte[(int) file.length()];
                fis.read(data);
                fis.close();
                System.out.println(new String(data));
            } else {
                System.err.println("Invalid file path.");
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

